var e=[{id:`L2_1`,type:`dialog`,speaker:`HUNTER_FRONTBAY_VETERAN_A`,text:{KOREA:`젠장, 방해되는 침식체들이 왜 이렇게 많아?`,JPN:`くそ、邪魔な侵食体が何でこんなに多いんだ？`,ENG:`Dammit, why are there so many C.O.s in the way?!`,TWN:`該死，怎麼這麼多礙事的侵蝕體？`},stage:{bg:`CLOSE`,bgm:`BATTLE_VIRTUAL`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HUNTER_FRONTBAY_VETERAN_A`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`HUNTER_FRONTBAY_VETERAN_B`,text:{KOREA:`잘 좀 쫓아봐! 이대로는 사냥감이 도망치겠어!`,JPN:`ちゃんと探してみろ！　このままだと獲物が逃げてしまうぞ！`,ENG:`Chase them out! Jackie's gonna get away!`,TWN:`快把他們趕走！到時候獵物跑掉！`},stage:{bg:`CLOSE`,bgm:`BATTLE_VIRTUAL`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`HUNTER_FRONTBAY_VETERAN_B`,face:`UNIT_IDLE`},C:{char_id:`HUNTER_FRONTBAY_VETERAN_A`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`상어 이빨 나가신다-!`,JPN:`サメの歯のお出ましー！`,ENG:`Here come the Sharks!`,TWN:`鯊魚露出牙齒囉！`},stage:{bg:`CLOSE`,bgm:`BATTLE_VIRTUAL`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`HUNTER_FRONTBAY_VETERAN_B`,face:`UNIT_IDLE`},C:{char_id:`HUNTER_FRONTBAY_VETERAN_A`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`HUNTER_FRONTBAY_VETERAN_A`,text:{KOREA:`윽? 이 목소리는 설마?!`,JPN:`うっ？　この声はまさか！？`,ENG:`Kgh? That voice...?!`,TWN:`嗯？這個聲音該不會是？！`},stage:{bg:`CLOSE`,bgm:`BATTLE_VIRTUAL`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`HUNTER_FRONTBAY_VETERAN_B`,face:`UNIT_IDLE`},C:{char_id:`HUNTER_FRONTBAY_VETERAN_A`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`HUNTER_FRONTBAY_VETERAN_B`,text:{KOREA:`해적 샤크스다! 우리가 노리는 타깃을 가로채러 온 거야!`,JPN:`海賊シャークスだ！　俺たちのターゲットを横取りに来たんだ！`,ENG:`It's the pirate Sharks! They're here to steal our target!`,TWN:`是前灣大白鯊！她們是來搶走我們的獵物的！`},stage:{bg:`CLOSE`,bgm:`BATTLE_VIRTUAL`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`HUNTER_FRONTBAY_VETERAN_B`,face:`UNIT_IDLE`},C:{char_id:`HUNTER_FRONTBAY_VETERAN_A`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`DRACO_NPC_SUMMER_NULL`,text:{KOREA:`캬하핫! 너흰 잡몹들이나 열심히 상대하고 있어. 엄-청 강력한 재키는 우리가 잘 처리해줄 테니까!`,JPN:`キャハハッ！　お前らは頑張ってじゃこの相手でもしていろよ。とーっても強力なジャッキーはあたしたちがちゃんと倒してあげるから！`,ENG:`Kya hah hah! Go play with the small fishies. We'll handle the mighty Jackie!`,TWN:`哇哈哈！你們就去對付那些小角色，杰克鯊鯊這個狠角色就交給我們處理吧！`},stage:{bg:`CLOSE`,bgm:`BATTLE_VIRTUAL`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DRACO_NPC_SUMMER_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`HUNTER_FRONTBAY_VETERAN_B`,text:{KOREA:`그렇겐 안 되지! 우린 저 망할 침식체 하나 때문에 육지를 나흘씩이나 못 밟았다고!`,JPN:`そうはさせない！　俺たちはあのクソ侵食体のせいで4日も陸に戻れてないんだ！`,ENG:`Not on my watch! We were out at sea for four days because of that damned C.O.!`,TWN:`那怎麼行！我們因為這個該死的侵蝕體，已經四天沒有上岸了。`},stage:{bg:`CLOSE`,bgm:`BATTLE_VIRTUAL`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DRACO_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`DRACO_NPC_SUMMER_NULL`,text:{KOREA:`응~ 그건 너희가 느려서 그런 거야~`,JPN:`うん～それはお前らが遅いからだね～`,ENG:`Whatever, ya slowpokes!`,TWN:`嗯～只能怪你們自己動作太慢吧～`},stage:{bg:`CLOSE`,bgm:`BATTLE_VIRTUAL`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DRACO_NPC_SUMMER_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`풉- 풉- 꼬우면 우리보다 빠르시던지~`,JPN:`ぷーぷー不満があるなら私たちより早く動くのです～`,ENG:`Pfft! Pfft! Why don't you just act faster?`,TWN:`噗噗，不服氣的話就來搶啊～`},stage:{bg:`CLOSE`,bgm:`BATTLE_VIRTUAL`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_SERIOUS2`},C:{char_id:`DRACO_NPC_SUMMER_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};